SELECT SUM(total_cases) AS total_cases_2020
FROM outbreaks
WHERE outbreak_year = 2020;

SELECT outbreak_id
FROM outbreaks
ORDER BY outbreak_year, outbreak_id;

SELECT COUNT(outbreak_id) AS total_outbreaks
FROM outbreaks
WHERE outbreak_year = 2023;

SELECT name, description
FROM etiologies
ORDER BY name ASC;

SELECT outbreak_id 
FROM outbreaks 
ORDER BY outbreak_id;

SELECT name
FROM etiologies
WHERE description LIKE '%virus%';

SELECT name, description
FROM etiologies
WHERE etiology_id IN (0, 1);
